import {
  Check,
  Copy,
  Download,
  Eye,
  EyeOff,
  History,
  Pencil,
  Settings2,
} from "lucide-react";

import {
  adjustmentLabels,
  getAdjustViewLabel,
  getEndAdjustLabel,
  getViewLabel,
} from "@/components/format-workspace/labels";
import { RulesListModal } from "@/components/format-workspace/rules-list-modal";
import type { EditMode, ViewMode } from "@/components/format-workspace/types";
import type { useFormatRules } from "@/components/format-workspace/use-format-rules";
import { Button } from "@/components/ui/button";

const outputViews: { value: ViewMode; label: string }[] = [
  { value: "reader", label: getViewLabel("reader") },
  { value: "markdown", label: getViewLabel("markdown") },
  { value: "handover", label: getViewLabel("handover") },
  { value: "json", label: getViewLabel("json") },
];

type CompletedToolbarProps = {
  adjustModeEnabled: boolean;
  copySuccess?: boolean;
  deletionsCount?: number;
  editMode: EditMode;
  isAdjustableView: boolean;
  rules: ReturnType<typeof useFormatRules>;
  showDeleted?: boolean;
  snapshotCount?: number;
  view: ViewMode;
  onCopyAll?: () => void;
  onDownloadMarkdown?: () => void;
  onEditModeChange: (mode: EditMode) => void;
  onToggleAdjustMode: () => void;
  onToggleShowDeleted?: () => void;
  onVersionsClick?: () => void;
  onViewChange: (view: ViewMode) => void;
};

export function CompletedToolbar({
  adjustModeEnabled,
  copySuccess,
  deletionsCount,
  editMode,
  isAdjustableView,
  rules,
  showDeleted,
  snapshotCount,
  view,
  onCopyAll,
  onDownloadMarkdown,
  onEditModeChange,
  onToggleAdjustMode,
  onToggleShowDeleted,
  onVersionsClick,
  onViewChange,
}: CompletedToolbarProps) {
  return (
    <div className="space-y-2">
      {/* Row 1: Format buttons */}
      <div data-testid="toolbar-format-row" className="flex flex-wrap gap-2">
        {outputViews.map((outputView) => (
          <Button
            key={outputView.value}
            data-testid={`format-view-${outputView.value}`}
            type="button"
            size="sm"
            variant={view === outputView.value ? "default" : "outline"}
            onClick={() => onViewChange(outputView.value)}
          >
            {outputView.label}
          </Button>
        ))}
      </div>

      {/* Row 2: Action buttons */}
      <div
        data-testid="toolbar-action-row"
        className="flex flex-wrap items-center gap-2"
      >
        {onDownloadMarkdown ? (
          <Button
            data-testid="toolbar-download"
            type="button"
            size="sm"
            variant="outline"
            onClick={onDownloadMarkdown}
          >
            <Download className="mr-2 h-4 w-4" />
            {adjustmentLabels.downloadAction}
          </Button>
        ) : (
          <Button
            data-testid="toolbar-download"
            type="button"
            size="sm"
            variant="outline"
            disabled
          >
            <Download className="mr-2 h-4 w-4" />
            {adjustmentLabels.downloadAction}
          </Button>
        )}

        {onCopyAll ? (
          <Button
            data-testid="toolbar-copy-all"
            type="button"
            size="sm"
            variant="outline"
            onClick={onCopyAll}
          >
            {copySuccess ? (
              <Check className="mr-2 h-4 w-4" />
            ) : (
              <Copy className="mr-2 h-4 w-4" />
            )}
            {copySuccess
              ? adjustmentLabels.copyAllSuccess
              : adjustmentLabels.copyAllAction}
          </Button>
        ) : (
          <Button
            data-testid="toolbar-copy-all"
            type="button"
            size="sm"
            variant="outline"
            disabled
          >
            <Copy className="mr-2 h-4 w-4" />
            {adjustmentLabels.copyAllAction}
          </Button>
        )}

        {snapshotCount && snapshotCount > 0 ? (
          <Button
            data-testid="toolbar-versions"
            type="button"
            size="sm"
            variant="outline"
            onClick={onVersionsClick}
          >
            <History className="mr-2 h-4 w-4" />
            {adjustmentLabels.versions}
          </Button>
        ) : null}

        {deletionsCount && deletionsCount > 0 ? (
          <Button
            type="button"
            size="sm"
            variant={showDeleted ? "default" : "outline"}
            onClick={onToggleShowDeleted}
          >
            {showDeleted ? (
              <EyeOff className="mr-2 h-4 w-4" />
            ) : (
              <Eye className="mr-2 h-4 w-4" />
            )}
            {showDeleted
              ? "Gelöschte ausblenden"
              : `${deletionsCount} gelöscht`}
          </Button>
        ) : null}

        {isAdjustableView ? (
          <>
            <RulesListModal
              disablingRuleById={rules.disablingRuleById}
              expandedRuleId={rules.expandedRuleId}
              explanationErrorById={rules.explanationErrorById}
              explanationLoadingById={rules.explanationLoadingById}
              promotingRuleById={rules.promotingRuleById}
              rules={rules.activeRules}
              view={view}
              getExplanationDetail={rules.getExplanationDetail}
              onDemoteRule={(ruleId) => {
                void rules.handleDemoteRule(ruleId);
              }}
              onDisableRule={(ruleId) => {
                void rules.handleDisableRule(ruleId);
              }}
              onHoverRule={(ruleId) => rules.setHoveredRuleId(ruleId)}
              onLeaveRule={() => rules.setHoveredRuleId(null)}
              onPromoteRule={(ruleId) => {
                void rules.handlePromoteRule(ruleId);
              }}
              onToggleRuleExplanation={rules.handleToggleRuleExplanation}
            />
            <Button
              data-testid={`toggle-adjust-mode-${view}`}
              type="button"
              size="sm"
              variant={adjustModeEnabled ? "default" : "outline"}
              onClick={onToggleAdjustMode}
            >
              <Settings2 className="mr-2 h-4 w-4" />
              {adjustModeEnabled
                ? getEndAdjustLabel()
                : getAdjustViewLabel(view)}
            </Button>
          </>
        ) : null}

        {view === "reader" ? (
          <Button
            data-testid="toggle-edit-mode"
            type="button"
            size="sm"
            variant={editMode === "edit" ? "default" : "outline"}
            onClick={() =>
              onEditModeChange(editMode === "edit" ? "view" : "edit")
            }
          >
            <Pencil className="mr-2 h-4 w-4" />
            {editMode === "edit"
              ? adjustmentLabels.endEdit
              : adjustmentLabels.edit}
          </Button>
        ) : null}
      </div>
    </div>
  );
}

import type {
  FormatRule,
  FormatRuleKind,
  ImportStage,
} from "@chat-exporter/shared";

import type { ViewMode } from "@/components/format-workspace/types";

const viewLabels: Record<ViewMode, string> = {
  reader: "Reader",
  markdown: "Markdown",
  handover: "Übergabe",
  json: "JSON",
};

const roleLabels: Record<string, string> = {
  assistant: "Assistent",
  markdown: "Markdown",
  system: "System",
  tool: "Werkzeug",
  user: "Nutzer",
};

const blockTypeLabels: Record<string, string> = {
  code: "Codeblock",
  heading: "Überschrift",
  list: "Liste",
  "markdown-lines": "Markdown-Zeilen",
  paragraph: "Absatz",
  quote: "Zitat",
  table: "Tabelle",
};

const ruleKindLabels: Record<FormatRuleKind, string> = {
  clipboard: "Zwischenablage",
  export_profile: "Export-Profil",
  inline_semantics: "Inline-Semantik",
  render: "Darstellung",
  structure: "Struktur",
};

// ---------------------------------------------------------------------------
// Job Status Labels
// ---------------------------------------------------------------------------

const jobStatusLabels: Record<string, string> = {
  completed: "Bereit",
  failed: "Fehlgeschlagen",
  queued: "Warteschlange",
  processing: "Import läuft",
};

export function getJobStatusLabel(status: string) {
  return jobStatusLabels[status] ?? jobStatusLabels.processing;
}

// ---------------------------------------------------------------------------
// Import Stage Labels
// ---------------------------------------------------------------------------

const importStageLabels: Record<
  ImportStage | "queued",
  { label: string; detail: string }
> = {
  queued: {
    label: "Wartet auf Start",
    detail:
      "Der Job ist in der Warteschlange und startet, sobald ein Worker frei ist.",
  },
  validate: {
    label: "Link wird geprüft",
    detail: "Der Link wird geprüft und dem passenden Importer zugeordnet.",
  },
  fetch: {
    label: "Seite wird geladen",
    detail: "Die freigegebene Seite wird geöffnet und als Quelle erfasst.",
  },
  extract: {
    label: "Nachrichten werden extrahiert",
    detail: "Die Unterhaltung wird aus dem Markup des Anbieters extrahiert.",
  },
  normalize: {
    label: "Transkript wird bereinigt",
    detail: "Rohfragmente werden in lesbare Nachrichten umgewandelt.",
  },
  structure: {
    label: "Struktur wird repariert",
    detail: "Abschnitte mit zusätzlichem Bereinigungsbedarf werden korrigiert.",
  },
  render: {
    label: "Ausgaben werden erzeugt",
    detail: "Reader- und Exportformate werden vorbereitet.",
  },
  done: {
    label: "Bereit",
    detail: "Das Transkript ist bereit.",
  },
};

export function getImportStageLabel(stage: ImportStage | "queued") {
  return importStageLabels[stage]?.label ?? stage;
}

export function getImportStageDescription(stage: ImportStage | "queued") {
  return importStageLabels[stage]?.detail ?? "";
}

export function getImportStageEntry(stage: ImportStage | "queued") {
  return importStageLabels[stage] ?? { label: stage, detail: "" };
}

// ---------------------------------------------------------------------------
// Adjustment UI Labels
// ---------------------------------------------------------------------------

export const adjustmentLabels = {
  // Button labels
  send: "Senden",
  sendPending: "Wird gesendet...",
  cancel: "Abbrechen",
  discard: "Verwerfen",
  dismiss: "Verstanden",
  download: "Download",

  // Placeholders
  adjustmentPlaceholder: "Beschreibe kurz, wie diese Stelle aussehen soll.",
  followUpPlaceholder: "Noch etwas anpassen?",

  // Messages
  loadingMessage: "Ich bereite diese Stelle gerade für die Anpassung vor.",
  appliedHint:
    "Die Änderung ist schon sichtbar. Du kannst weiter anpassen oder eine neue Stelle markieren.",
  defaultHint:
    "Die KI antwortet kurz und setzt klare Änderungen sofort direkt in dieser Ansicht um.",
  closeLabel: "Anpassung schließen",
  createRuleLabel: "Regel erstellen",
  inputLabel: "Anpassungsanfrage",

  // Guide
  guideInstruction:
    "Markiere die Stelle, die anders aussehen soll. Beschreibe dann kurz deinen Wunsch, und die Änderung erscheint direkt hier.",
  guideNote: "Du musst kein Regel-JSON lesen oder eine Vorschau vergleichen.",

  // Mode toggle
  endAdjustMode: "Anpassungsmodus beenden",

  // Edit mode
  edit: "Bearbeiten",
  endEdit: "Bearbeitung beenden",

  // Clipboard
  copied: "Kopiert!",

  // Toolbar actions
  versions: "Versionen",
  downloadAction: "Herunterladen",
  copyAllAction: "Kopieren",
  copyAllSuccess: "Kopiert!",
} as const;

export function getAdjustViewLabel(view: ViewMode) {
  return `${getViewLabel(view)} anpassen`;
}

export function getEndAdjustLabel() {
  return adjustmentLabels.endAdjustMode;
}

// ---------------------------------------------------------------------------
// View Labels
// ---------------------------------------------------------------------------

export function getViewLabel(view: ViewMode) {
  return viewLabels[view];
}

export function getRoleLabel(role: string) {
  return roleLabels[role] ?? role;
}

export function getBlockTypeLabel(blockType: string) {
  return blockTypeLabels[blockType] ?? blockType;
}

export function getRuleKindLabel(kind: FormatRuleKind) {
  return ruleKindLabels[kind];
}

// ---------------------------------------------------------------------------
// Selection Formatter
// ---------------------------------------------------------------------------

export function formatMarkdownLinesLabel(start: number, end: number) {
  return `Markdown-Zeilen ${start}-${end}`;
}

export function formatMessageBlockLabel(
  role: string,
  index: number,
  blockType: string,
) {
  return `${getRoleLabel(role)}-Nachricht ${index} · ${getBlockTypeLabel(blockType)}`;
}

// ---------------------------------------------------------------------------
// Rules Labels
// ---------------------------------------------------------------------------

export const rulesLabels = {
  activeRulesCount: (count: number) =>
    count > 0 ? `${count} ${count === 1 ? "Regel" : "Regeln"} aktiv` : "Regeln",
  noActiveRules: "Keine aktiven Regeln.",
  allImports: "Für alle Imports",
  thisImportOnly: "Nur dieser Import",
  loading: "Wird geladen...",
  rationale: "Begründung",
  defaultRationale:
    "Diese Regel wurde aus einer früheren Anpassungssession für diesen Import erzeugt.",
  exactScopeNote: "Diese Regel gilt nur für die ursprüngliche Auswahl.",
  globalScopeNote: "Diese Regel gilt für alle Imports in diesem Format.",
  undoPending: "Wird rückgängig gemacht...",
  undo: "Rückgängig",
} as const;

// ---------------------------------------------------------------------------
// Loading & Misc Labels
// ---------------------------------------------------------------------------

export const miscLabels = {
  transcriptLoading: "Transkript wird vorbereitet",
  importFailed: "Import fehlgeschlagen",
  errorInPhase: (phase: string) => `Fehler in Phase: ${phase}`,
  viewLoadError: "Diese Ansicht konnte nicht geladen werden.",
  retryButton: "Erneut versuchen",
  adjustmentLoadError: "Anpassungen konnten nicht geladen werden.",
} as const;

export function getRuleLabel(rule: FormatRule) {
  const summary = rule.instruction.trim();

  if (summary.length <= 72) {
    return summary;
  }

  return `${summary.slice(0, 69).trimEnd()}...`;
}

