 85→export function FormatWorkspace({
 86→  activeStage,
 87→  elapsedTime,
 88→  job,
 89→  view,
 90→  onViewChange,
 91→}: FormatWorkspaceProps) {
 92→  const isAdjustableView = adjustableViews.has(view);
 93→
 94→  const session = useAdjustmentSession(view, job.id);
 95→  const rules = useFormatRules(view, job.id);
 96→  const snapshots = useSnapshots(job.id);
 97→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 98→  const resolvedMessages = useResolvedConversation(
 99→    job.conversation,
100→    messageEdits.editedMessagesMap,
101→  );
102→  const autoSnapshot = useAutoSnapshot({
