137→    const handler = (e: BeforeUnloadEvent) => {
138→      e.preventDefault();
139→    };
140→    window.addEventListener("beforeunload", handler);
141→    return () => window.removeEventListener("beforeunload", handler);
142→  }, [messageEdits.hasPendingEdits]);
