  1→// ---------------------------------------------------------------------------
  2→// OutputFormatDescriptor — Step 1
  3→// ---------------------------------------------------------------------------
  4→
  5→export interface OutputFormatDescriptor {
  6→  /** Unique ID, e.g. "reader", "markdown" */
  7→  id: string;
  8→  /** Display name for the UI, e.g. "Reader View" */
  9→  label: string;
 10→  /** Whether this format supports adjustments/rules */
 11→  adjustable: boolean;
 12→  /** Which RuleEffect types this format supports */
 13→  supportedRuleKinds: readonly string[];
 14→  /** MIME type for export download */
 15→  exportMimeType: string;
 16→  /** File extension for export download */
 17→  exportExtension: string;
 18→}
 19→
 20→// ---------------------------------------------------------------------------
 21→// Built-in Format Descriptors — Step 2
 22→// ---------------------------------------------------------------------------
 23→
 24→export const BUILTIN_FORMATS: readonly OutputFormatDescriptor[] = [
 25→  {
 26→    id: "reader",
 27→    label: "Reader",
 28→    adjustable: true,
 29→    supportedRuleKinds: [
 30→      "adjust_block_spacing",
 31→      "increase_heading_emphasis",
 32→      "refine_selected_block_presentation",
 33→      "bold_prefix_before_colon",
 34→      "render_markdown_strong",
 35→      "custom_style",
 36→    ],
 37→    exportMimeType: "text/html",
 38→    exportExtension: ".html",
 39→  },
 40→  {
 41→    id: "markdown",
 42→    label: "Markdown",
 43→    adjustable: true,
 44→    supportedRuleKinds: [
 45→      "promote_to_heading",
 46→      "bold_prefix_before_colon",
 47→      "normalize_list_structure",
 48→      "normalize_markdown_table",
 49→      "reshape_markdown_block",
 50→      "custom_style",
 51→    ],
 52→    exportMimeType: "text/markdown",
 53→    exportExtension: ".md",
 54→  },
 55→  {
 56→    id: "handover",
 57→    label: "Übergabe",
 58→    adjustable: false,
 59→    supportedRuleKinds: [],
 60→    exportMimeType: "text/plain",
 61→    exportExtension: ".txt",
 62→  },
 63→  {
 64→    id: "json",
 65→    label: "JSON",
 66→    adjustable: false,
 67→    supportedRuleKinds: [],
 68→    exportMimeType: "application/json",
 69→    exportExtension: ".json",
 70→  },
 71→];
 72→
 73→// ---------------------------------------------------------------------------
 74→// FormatRegistry — Step 3
 75→// ---------------------------------------------------------------------------
 76→
 77→export class FormatRegistry {
 78→  private formats = new Map<string, OutputFormatDescriptor>();
 79→
 80→  register(format: OutputFormatDescriptor): void {
 81→    if (this.formats.has(format.id)) {
 82→      throw new Error(`Format "${format.id}" is already registered.`);
 83→    }
 84→    this.formats.set(format.id, format);
 85→  }
 86→
 87→  get(id: string): OutputFormatDescriptor | undefined {
 88→    return this.formats.get(id);
 89→  }
 90→
 91→  getAll(): OutputFormatDescriptor[] {
 92→    return [...this.formats.values()];
 93→  }
 94→
 95→  getAdjustable(): OutputFormatDescriptor[] {
 96→    return this.getAll().filter((f) => f.adjustable);
 97→  }
 98→
 99→  supportsRuleKind(formatId: string, ruleKind: string): boolean {
100→    const format = this.formats.get(formatId);
101→    if (!format) return false;
102→    return format.supportedRuleKinds.includes(ruleKind);
103→  }
104→}
105→
106→export const defaultRegistry = new FormatRegistry();
107→for (const format of BUILTIN_FORMATS) {
108→  defaultRegistry.register(format);
109→}
