 50→type FormatWorkspaceProps = {
 51→  activeStage: ActiveStage;
 52→  elapsedTime: string;
 53→  job: ImportJob;
 54→  view: ViewMode;
 55→  onViewChange: (view: ViewMode) => void;
 56→};
