454→        </div>
455→      ) : job.status === "queued" || job.status === "running" ? (
456→        <LoadingStateBlock stageDetail={activeStage?.detail} />
457→      ) : (
458→        <div className="space-y-4">
459→          <CompletedToolbar
460→            adjustModeEnabled={session.adjustModeEnabled}
