520→                content={displayedMarkdown}
521→                adjustModeEnabled={session.adjustModeEnabled}
522→                highlightedRuleId={rules.hoveredRuleId}
523→                selectedRange={session.activeSelection}
524→                onSelectLines={session.handleSelectionChange}
525→              />
526→            </ErrorBoundary>
527→          ) : (
528→            <ErrorBoundary fallback={viewErrorFallback}>
529→              <ArtifactView content={artifact} />
530→            </ErrorBoundary>
531→          )}
532→
533→          {session.showGuide ? (
534→            <AdjustmentModeGuide
535→              view={view}
536→              onDismiss={() => session.setGuideDismissed(true)}
537→            />
538→          ) : null}
539→
540→          <ErrorBoundary
541→            fallback={
542→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
543→                {miscLabels.adjustmentLoadError}
544→              </div>
545→            }
546→          >
547→            <AdjustmentPopover
548→              anchor={session.activeAnchor ?? null}
549→              containerRef={session.sectionRef}
550→              draftMessage={session.activeDraftMessage}
551→              error={session.activeSessionError}
552→              isLoading={session.activeSessionLoading || session.isDiscarding}
553→              isSubmitting={session.isSubmitting}
554→              open={
555→                showPopover &&
556→                Boolean(session.activeSelection) &&
557→                Boolean(session.activeAnchor)
558→              }
559→              sessionDetail={session.activeSessionDetail}
560→              showReply={session.replyVisible}
561→              view={view}
562→              onClose={handlePopoverClose}
563→              onDraftMessageChange={session.handleDraftMessageChange}
564→              onRejectLastChange={handleRejectLastChange}
565→              onSubmitMessage={session.handleSubmitMessage}
566→            />
567→          </ErrorBoundary>
568→        </div>
569→      )}
570→
571→      {deleteDialog && (
572→        <DeleteMessageDialog
573→          messagePreview={deleteDialog.preview}
574→          isRound={deleteDialog.isRound}
575→          onConfirm={(reason) => {
576→            void handleConfirmDelete(reason);
577→          }}
578→          onCancel={() => setDeleteDialog(null)}
579→        />
580→      )}
581→
582→      {deletionToast.toast && (
583→        <UndoToast
584→          message={deletionToast.toast.message}
585→          onUndo={() => {
