587→          }}
588→          onDismiss={deletionToast.dismissToast}
589→        />
590→      )}
591→
592→      <VersionsModal
593→        open={versionsModalOpen}
594→        onOpenChange={setVersionsModalOpen}
595→        snapshots={snapshots.snapshots}
596→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
597→        onActivate={(snapshotId) => {
598→          void snapshots.activate(snapshotId);
599→        }}
600→        onDeactivate={() => {
601→          void snapshots.deactivate();
602→        }}
603→        onCreate={(label) => {
604→          void snapshots.create(label);
605→        }}
606→        onRename={(snapshotId, label) => {
607→          void snapshots.rename(snapshotId, label);
608→        }}
609→        onDelete={(snapshotId) => {
610→          void snapshots.delete(snapshotId);
611→        }}
612→      />
613→    </section>
614→  );
615→}
